root.js-content:
stp.writeLog("Start: assing msg to Receive Amend Agreement");
stp.setFunc("Receive Amend Agreement", "Scf Programer Maintenance");
var sType = stp.getMsgTagVal("FA_BUSI_TYPE");
var iLen= sType.toString().length();
if(iLen == 0){
    sType = stp.getXslMsgTagVal("message/out-msg-content/trx","FA_BUSI_TYPE");
}
if(sType == "SF" || sType == "DD" ){
  stp.setCustomXSLName("stp.fada.007.rf");
  stp.setIsUseXSLMapping(true);
} else if(sType == "RD"){
  stp.setCustomXSLName("stp.fada.007.df");
  stp.setIsUseXSLMapping(true);
}
stp.writeLog("sType****************"+sType);
stp.writeLog("End: assing msg to Receive Amend Agreement");
